package dev.harrison.rendacomcarro.finance.domain;
import jakarta.persistence.*;import java.math.*;import java.time.*;import java.util.UUID;
@Entity @Table(name="obligation_payment") public class ObligationPayment {@Id private UUID id;@ManyToOne(fetch=FetchType.LAZY,optional=false)@JoinColumn(name="obligation_id")private FinancialObligation obligation;@ManyToOne(fetch=FetchType.LAZY)@JoinColumn(name="installment_id")private ObligationInstallment installment;@Column(name="payment_date",nullable=false)private LocalDate paymentDate;@Column(nullable=false,precision=14,scale=2)private BigDecimal amount;@Column(name="principal_paid",nullable=false,precision=14,scale=2)private BigDecimal principalPaid;@Column(name="interest_paid",nullable=false,precision=14,scale=2)private BigDecimal interestPaid;@Column(name="extra_amortization",nullable=false,precision=14,scale=2)private BigDecimal extraAmortization;@Column(name="external_reference")private String externalReference;@Column(columnDefinition="text")private String notes;@Column(name="created_at",nullable=false)private LocalDateTime createdAt;protected ObligationPayment(){}public static ObligationPayment create(FinancialObligation o,LocalDate date,BigDecimal principal,BigDecimal interest,BigDecimal extra,String ref,String notes){ObligationPayment p=new ObligationPayment();p.id=UUID.randomUUID();p.obligation=o;p.paymentDate=date;p.principalPaid=principal;p.interestPaid=interest;p.extraAmortization=extra;p.amount=principal.add(interest).add(extra);p.externalReference=ref;p.notes=notes;p.createdAt=LocalDateTime.now();return p;}public UUID getId(){return id;}public LocalDate getPaymentDate(){return paymentDate;}public BigDecimal getAmount(){return amount;}public BigDecimal getPrincipalPaid(){return principalPaid;}public BigDecimal getInterestPaid(){return interestPaid;}public BigDecimal getExtraAmortization(){return extraAmortization;}public String getExternalReference(){return externalReference;}public String getNotes(){return notes;}}
